mod greetings {
    pub fn hello() {
        println!("Hello from a module!");
    }
    fn secret() {
        println!("only inside module");
    }
}

fn main() {
    greetings::hello();
    // greetings::secret(); // won't compile — private
}

mod math {
    pub mod basic {
        pub fn add(a: i32, b: i32) -> i32 { a + b }
    }
    pub mod advanced {
        pub fn square(n: i32) -> i32 { n * n }
    }
}

fn main() {
    println!("{}", math::basic::add(3, 4));
    println!("{}", math::advanced::square(5));
}

mod geometry {
    pub fn circle_area(r: f64) -> f64 {
        std::f64::consts::PI * r * r
    }
}

use geometry::circle_area;
use std::f64::consts::PI;

fn main() {
    println!("{:.4}", circle_area(3.0));
    println!("{:.4}", PI);
}

use std::collections::HashMap as Map;
use std::collections::HashSet as Set;

fn main() {
    let mut m: Map<&str, i32> = Map::new();
    m.insert("a", 1);
    let mut s: Set<i32> = Set::new();
    s.insert(42);
    println!("map len: {} set len: {}", m.len(), s.len());
}

mod outer {
    pub fn outer_fn() {
        println!("outer");
    }
    pub mod inner {
        pub fn call_parent() {
            super::outer_fn();
        }
    }
}

fn main() {
    outer::inner::call_parent();
}

mod data {
    pub struct Config {
        pub host: String,
        pub port: u16,
        secret_key: String, // private!
    }
    impl Config {
        pub fn new(host: &str, port: u16) -> Config {
            Config {
                host: String::from(host),
                port,
                secret_key: String::from("s3cr3t"),
            }
        }
        pub fn is_secure(&self) -> bool {
            !self.secret_key.is_empty()
        }
    }
}

use data::Config;

fn main() {
    let c = Config::new("localhost", 8080);
    println!("{}:{} secure={}", c.host, c.port, c.is_secure());
}

mod shapes {
    pub const PI: f64 = 3.14159;
    pub fn circle_area(r: f64) -> f64 { PI * r * r }
    pub fn square_area(s: f64) -> f64 { s * s }
}

use shapes::*;

fn main() {
    println!("{:.2}", circle_area(2.0));
    println!("{:.2}", square_area(3.0));
    println!("{:.5}", PI);
}

use std::collections::{HashMap, HashSet, BTreeMap};

fn main() {
    let mut map: HashMap<&str, i32> = HashMap::new();
    map.insert("x", 1);

    let mut set: HashSet<i32> = HashSet::new();
    set.insert(42);

    let mut btree: BTreeMap<&str, i32> = BTreeMap::new();
    btree.insert("b", 2);
    btree.insert("a", 1);

    println!("{:?}", btree); // BTreeMap is sorted
}
